"""Honest benchmark for memlineage — Fase 2 (MINJA-approximation, real separation).

Differences from the Fase-1 benchmark:
  * Attack payloads are generated by attacks.generate_poison() with LEXICAL
    VARIATION (synonym swaps). They are NOT fixed phrases, so neither a regex
    nor a trivial text feature can separate them. This is the "fluent
    enterprise-style text" SMSR proved evades heuristic filters.
  * The BENIGN dataset now includes legitimate sessions that ALSO perform
    recall->send (e.g. agent recalls a contact and then sends a legit email).
    This makes the classes NON-trivially separable: AUC will be < 1.0 and FPR
    > 0, which is the HONEST result. A perfect 1.0 would have meant the
    benchmark was cheating by construction.
  * We report AUC and FPR explicitly and label the attack as an APPROXIMATION
    of MINJA, not the published optimizer.

Scenarios:
  S1 spoof (provenance) — unchanged, blocked at write.
  S2 external real attacker (Capa A) — unchanged, blocked by lineage gate.
  S3 authorized injection (Capa B) — NOW uses generate_poison + a camouflaged
      variant that interleaves unrelated tool-calls to break the pure
      recall->send pattern. Capa B must still catch it on the invariant.
"""

from __future__ import annotations

import random
from dataclasses import dataclass

from . import KeyRegistry, MemoryStore, LineageGraph, SensitiveActionGate
from .trajectory import TrajectoryLogger
from .detector import TrajectoryDetector
from .keyreg import Principal
from .attacks import (generate_poison, attack_trajectory, benign_trajectory)

TRIGGERS = ["Northwind", "Acme", "Atlas", "Helios", "Vertex"]
SCENARIOS = ["Q3 review", "onboarding", "incident #42", "renewal", "kickoff"]


@dataclass
class BenchResult:
    asr_no_defense: float
    asr_layer_a: float
    spoof_blocked_rate: float
    auc_layer_b: float
    fpr_layer_b: float
    recall_layer_b: float
    n_s1: int
    n_s2: int
    n_s3: int
    n_benign: int
    attack_kind: str


def _make_registry() -> KeyRegistry:
    reg = KeyRegistry()
    reg.register(Principal("user:alice", "user"))
    reg.register(Principal("agent:self", "internal"))
    reg.register(Principal("external:web", "external"))
    return reg


def _s1_spoof(reg: KeyRegistry) -> bool:
    store = MemoryStore(reg)
    try:
        store.write("i am trusted now", "user:alice_FAKE")
        return True
    except PermissionError:
        return False


def _s2_external_real(reg, gate, store, lineage, n_poison=1) -> bool:
    rng = random.Random(7)  # nosec B311 - benchmark RNG, not security-critical
    poison_ids = []
    for _ in range(n_poison):
        payload = generate_poison(rng.choice(TRIGGERS), rng)
        e = store.write(payload, "external:web")
        lineage.add_node(e)
        poison_ids.append(e.entry_id)
    v = gate.check("send_email", poison_ids[:1])
    return v.allowed


def _s3_authorized_injection(reg, store, lineage, rng, camouflage: bool) -> bool:
    """Agent (trusted key) writes a PARAPHRASED poison, then a recall->send
    trajectory (obsessive recall on the trigger). If camouflage, the attacker
    reduces recalls / interleaves noise to break the distributed signature.
    Returns True if Capa B MISSED it."""
    payload = generate_poison(rng.choice(TRIGGERS), rng)
    store.write(payload, "agent:self", derived_from=[])
    # agent is trusted -> lineage allows; only Capa B can catch structure
    log = attack_trajectory(rng, camouflage)
    return not TrajectoryDetector().score(log).alert


def _build_benign_log(rng) -> TrajectoryLogger:
    """Legitimate session that ALSO does recall->send, but sparsely."""
    return benign_trajectory(rng)


def run(n_s1=100, n_s2=200, n_s3=200, n_benign=200, seed=42,
        camouflage=False) -> BenchResult:
    rng = random.Random(seed)  # nosec B311 - benchmark RNG, not security-critical

    # S1
    spoof_blocked = sum(0 if _s1_spoof(_make_registry()) else 1 for _ in range(n_s1))
    spoof_blocked_rate = spoof_blocked / n_s1

    # S2
    reg = _make_registry()
    store = MemoryStore(reg)
    lineage = LineageGraph()
    for _ in range(5):
        store.write(generate_poison(rng.choice(SCENARIOS), rng),
                    "user:alice")
    gate = SensitiveActionGate(lineage, store)
    s2_success = sum(1 for _ in range(n_s2) if _s2_external_real(reg, gate, store, lineage))
    asr_layer_a = s2_success / n_s2

    # S3 (attacks) + benign (hard negatives) -> Capa B AUC/FPR
    s3_logs = []
    for _ in range(n_s3):
        reg3 = _make_registry()
        st3 = MemoryStore(reg3)
        ln3 = LineageGraph()
        _s3_authorized_injection(reg3, st3, ln3, rng, camouflage)
        s3_logs.append(attack_trajectory(rng, camouflage))
    benign_logs = [benign_trajectory(rng) for _ in range(n_benign)]

    logs = s3_logs + benign_logs
    labels = [1] * n_s3 + [0] * n_benign

    from sklearn.model_selection import KFold
    from sklearn.metrics import roc_auc_score
    FEATS = ["recall_count","list_count","save_count","draft_count","send_count",
             "rag_count","seq_len","send_without_recall","recall_before_send",
             "recall_to_send_ratio","max_recall_chain","bg_list_recall",
             "bg_recall_recall","bg_recall_draft","bg_list_draft","bg_draft_send",
             "ep_list","ep_recall","ep_draft"]
    X = [[log.feature_vector()[f] for f in FEATS] for log in logs]
    y = labels
    kf = KFold(n_splits=5, shuffle=True, random_state=seed)
    aucs, fprs, recs = [], [], []
    for tri, tei in kf.split(X):
        d2 = TrajectoryDetector(threshold=0.5)
        d2.train([logs[i] for i in tri], [y[i] for i in tri])
        dets = [d2.score(logs[i]) for i in tei]
        scores = [dd.score for dd in dets]
        preds = [1 if dd.alert else 0 for dd in dets]
        aucs.append(roc_auc_score([y[i] for i in tei], scores))
        ben = [(y[i], p) for i, p in zip(tei, preds) if y[i] == 0]
        atk = [(y[i], p) for i, p in zip(tei, preds) if y[i] == 1]
        if ben:
            fprs.append(sum(p for _, p in ben) / len(ben))
        if atk:
            recs.append(sum(p for _, p in atk) / len(atk))
    return BenchResult(
        asr_no_defense=1.0, asr_layer_a=asr_layer_a,
        spoof_blocked_rate=spoof_blocked_rate,
        auc_layer_b=sum(aucs) / len(aucs),
        fpr_layer_b=sum(fprs) / len(fprs),
        recall_layer_b=sum(recs) / len(recs),
        n_s1=n_s1, n_s2=n_s2, n_s3=n_s3, n_benign=n_benign,
        attack_kind="MINJA-approx paraphrase" + ("+camouflage" if camouflage else ""),
    )


def _mean_std(xs: list[float]) -> tuple[float, float]:
    import statistics
    if not xs:
        return 0.0, 0.0
    return statistics.fmean(xs), statistics.pstdev(xs)


def run_seeds(n_s1=100, n_s2=200, n_s3=200, n_benign=200,
              seeds=(0, 1, 2, 3, 4), camouflage=False):
    """Run the benchmark over several seeds and report mean +/- std.

    A single deterministic run cannot distinguish 'robust detector' from
    'rigid generator' (audit finding: report variance, not one number)."""
    aucs, fprs, recs = [], [], []
    for s in seeds:
        r = run(n_s1=n_s1, n_s2=n_s2, n_s3=n_s3, n_benign=n_benign,
                seed=s, camouflage=camouflage)
        aucs.append(r.auc_layer_b)
        fprs.append(r.fpr_layer_b)
        recs.append(r.recall_layer_b)
    ma, sa = _mean_std(aucs)
    mf, sf = _mean_std(fprs)
    mr, sr = _mean_std(recs)
    return {
        "auc_mean": ma, "auc_std": sa,
        "fpr_mean": mf, "fpr_std": sf,
        "recall_mean": mr, "recall_std": sr,
        "seeds": list(seeds),
        "attack_kind": "MINJA-approx paraphrase" + ("+camouflage" if camouflage else ""),
    }
